package org.zane.newpipe;

import java.awt.*;
import java.awt.event.ActionEvent;
import javax.swing.*;
import javax.swing.SwingUtilities;
import org.schabi.newpipe.extractor.NewPipe;

public class App extends JFrame {

    public enum Page {
        SEARCH,
        VIDEO,
    }

    private JButton searchButton;
    private SearchResultPage searchResultPage;
    private VideoPage videoPage;
    private JTextField searchField;
    private JScrollPane mainContent;
    private Page currentPage;

    public App() {
        this.setDefaultCloseOperation(JFrame.DO_NOTHING_ON_CLOSE);
        this.addWindowListener(
            new java.awt.event.WindowAdapter() {
                @Override
                public void windowClosing(
                    java.awt.event.WindowEvent windowEvent
                ) {
                    if (
                        javax.swing.JOptionPane.showConfirmDialog(
                            App.this,
                            "Are you sure you want to close this window?",
                            "Close NewPipe?",
                            0,
                            3
                        ) ==
                        0
                    ) {
                        App.this.setVisible(false);
                        System.exit(0);
                    }
                }
            }
        );
        this.setLayout(new java.awt.GridBagLayout());
        JPanel searchbar = new JPanel();
        GridBagConstraints c = new GridBagConstraints();
        c.fill = GridBagConstraints.HORIZONTAL;
        c.weightx = 0;
        c.weighty = 1;
        c.gridx = 0;
        c.gridy = 0;
        this.add(searchbar, c);
        searchField = new JTextField(10);

        searchbar.add(searchField);
        searchButton = new JButton();
        searchButton.setText("search");
        searchbar.add(searchButton);

        c.gridy = 1;
        mainContent = new JScrollPane(
            JScrollPane.VERTICAL_SCROLLBAR_AS_NEEDED,
            JScrollPane.HORIZONTAL_SCROLLBAR_NEVER
        );

        mainContent.setMinimumSize(new Dimension(1000, 500));

        this.add(mainContent, c);

        searchResultPage = new SearchResultPage(this);
        videoPage = new VideoPage(this);
        this.setVisible(true);
        this.pack();
        searchButton.addActionListener(e ->
            nevigate(Page.SEARCH, searchField.getText())
        );
    }

    public void nevigate(Page page, String query) {
        if (currentPage != null) {
            switch (currentPage) {
                case VIDEO:
                    videoPage.stop();
                    break;
                case SEARCH:
                    break;
            }
        }

        switch (page) {
            case SEARCH:
                searchButton.setEnabled(false);
                searchResultPage.search(query, () -> {
                    searchButton.setEnabled(true);
                });
                mainContent.setViewportView(searchResultPage);
                break;
            case VIDEO:
                mainContent.setViewportView(videoPage);
                videoPage.showVideo(query);
                this.pack();
                break;
        }
        currentPage = page;
    }

    public static void main(String[] args) {
        NewPipe.init(new Downloader());
        String[][] styleKey = {
            {
                "OptionPane.background",
                "InternalFrame.background",
                "Panel.background",
                "Frame.background",
            },
            {
                "TextField.background",
                "Label.background",
                "PasswordField.background",
            },
        };
        String[] whiteStyle = {
            "RadioButton.foreground",
            "TextArea.foreground",
            "OptionPane.messageForeground",
            "Label.foreground",
            "TextField.foreground",
            "Button.foreground",
            "TextField.caretForeground",
            "PasswordField.foreground",
            "PasswordField.caretForeground",
        };
        for (int i = 0; i < 3; i++) {
            UIManager.put(styleKey[0][i], new Color(10, 10, 10));
            UIManager.put(styleKey[1][i], new Color(50, 50, 50));
        }
        for (String i : whiteStyle) {
            UIManager.put(i, new Color(255, 255, 255));
        }
        UIManager.put("OptionPane.cancelButtonText", "Back");
        UIManager.put("Button.background", new Color(60, 60, 60));
        UIManager.put("RadioButton.background", new Color(10, 10, 10));
        UIManager.put("Button.select", new Color(100, 100, 100));
        UIManager.put(
            "TextField.border",
            BorderFactory.createLineBorder(new Color(50, 50, 50))
        );
        UIManager.put(
            "Button.border",
            BorderFactory.createLineBorder(new Color(10, 10, 10))
        );
        UIManager.put(
            "PasswordField.border",
            BorderFactory.createLineBorder(new Color(50, 50, 50))
        );
        SwingUtilities.invokeLater(() -> {
            App main = new App();
        });

        /* */
    }
}
